seo.schema:
{
    "@context": "https://schema.org",
    "@graph": [
        {
            "@type": "HomeAndConstructionBusiness",
            "@id": "{website}/#localbusiness",
            "name": "{business}",
            "url": "{website}",
            "telephone": "{tel}",
            "description": "{business} connects {state} property owners with trained water and storm damage restoration specialists, providing 24/7 emergency water extraction, structural drying, and flood, storm, and sewage cleanup for homes and businesses.",
            "areaServed": {
                "@type": "State",
                "name": "{state}"
            },
            "priceRange": "$$",
            "openingHours": "Mo-Su 00:00-23:59"
        },
        {
            "@type": "WebSite",
            "@id": "{website}/#website",
            "url": "{website}",
            "name": "{business}",
            "publisher": {
                "@id": "{website}/#localbusiness"
            }
        }
    ]
}
